#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output) {
    const int N = static_cast<int>(x.size());
    output.resize(N);                                // no need to init to 0, will be overwritten

    // Pre‑compute the twiddle factors once per n
    std::vector<std::complex<double>> twiddles(N);
    for (int n = 0; n < N; ++n) {
        double const factor = 2.0 * M_PI * n / N;
        twiddles[n] = std::exp(std::complex<double>(0.0, -factor));
    }

    // Parallelize over output indices (k)
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        double const factor = 2.0 * M_PI * k / N;
        for (int n = 0; n < N; ++n) {
            std::complex<double> c = std::exp(std::complex<double>(0.0, -factor * n));
            sum += x[n] * c;
        }
        output[k] = sum;
    }
}
