void firstLetterCounts(const std::vector<std::string>& s,
                       std::array<size_t, 26>& bins) {
    // Zero out the output array once.
    bins.fill(0);

    // Determine a suitable chunk size for parallelization.
    constexpr int CHUNK = 64;

    // Check if we should run in parallel.
    if (s.size() < 2 * 1024) {
        // For very small inputs serialize to avoid overhead.
        for (size_t i = 0; i < s.size(); ++i) {
            bins[static_cast<unsigned char>(s[i][0] - 'a')]++;
        }
        return;
