        std::array<size_t, 26> local = {0};

#pragma omp for schedule(static, CHUNK) nowait
        for (size_t i = 0; i < s.size(); ++i) {
            const unsigned char c = static_cast<unsigned char>(s[i][0] - 'a');
            // The input is guaranteed to be lowercase a..z.
            local[c]++;
        }

#pragma omp critical
        {
            for (int j = 0; j < 26; ++j) bins[j] += local[j];
        }
