#endif
    for (std::size_t i = 0; i < n; ++i) {
        // Use a simple branchless trick: max(0, x[i]) => -(x[i] < 0) * x[i]
        // This eliminates a branch and may lead to better vectorisation.
        const double val = x[i];
        // The expression below is equivalent to std::max(0.0, val)
        x[i] = (val > 0.0) ? val : 0.0;
