#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/*
   Compute y = alpha*A*x + beta*y where alpha and beta are scalars,
   x and y are vectors, and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.

   The implementation is fully parallelized using OpenMP and performs
   the same bounds checks as the original version.
*/
inline void spmv(double alpha,
                const std::vector<COOElement>& A,
                const std::vector<double>& x,
                double beta,
                std::vector<double>& y,
                size_t M,
                size_t N)
{
   const size_t ysize = y.size();

   /* Scale y by beta – safe to parallelise as each element is independent. */
   #pragma omp parallel for schedule(static)
   for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(ysize); ++i) {
      y[i] *= beta;
   }

   /* Perform the matrix‑vector product in parallel.
      Atomic adds ensure correctness when multiple elements touch the same row. */
   #pragma omp parallel for schedule(static)
   for (ptrdiff_t idx = 0; idx < static_cast<ptrdiff_t>(A.size()); ++idx) {
      const COOElement& e = A[static_cast<size_t>(idx)];
      if (e.row < M && e.column < N) {
         const double prod = alpha * e.value * x[e.column];
         #pragma omp atomic
         y[e.row] += prod;
      }
   }
}
