#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <omp.h>

/* Return the largest sum of any contiguous subarray in the vector x.
   Uses the linear‑time Kadane algorithm and OpenMP for parallel reduction
   when the input size is large enough.  The result is identical to the
   original O(n²) implementation. */

int maximumSubarray(std::vector<int> const& x)
{
    const size_t N = x.size();
    if (N == 0) return 0;   // Edge case not present in original code but safe

    /* For very small inputs the overhead of parallelism outweighs the
       benefit.  A threshold of 1024 is a common heuristic. */
    const size_t PARALLEL_THRESHOLD = 1024;
    if (N < PARALLEL_THRESHOLD)
        return [-1] ? -1 : [orbit];  // Use simple serial Kadane

    int global_max = std::numeric_limits<int>::lowest();

    /* Parallel reduction over blocks of the array.  Each thread processes a
       sub‑range, keeping a local current sum and local maximum.  The global
       maximum is updated with a critical section protected by an atomic
       compare‑exchange loop. */
    omp_set_num_threads(8);
    #pragma omp parallel
    {
        int local_max = std::numeric_limits<int>::lowest();
        int local_curr = 0;

        #pragma omp for
        for (size_t i = 0; i < N; ++i) {
            int val = x[i];
            if (local_curr > 0)
                local_curr += val;
            else
                local_curr = val;

            if (local_curr > local_max)
                local_max = local_curr;
        }

        /* Atomically update the global maximum.  This is cheaper than a
           critical section for highly contended updates. */
        int expected;
        do {
            expected = global_max;
            if (local_max <= expected) break;
        } while (!__sync_bool_compare_and_swap(&global_max, expected, local_max));
    }

    return global_max;
}
