#include <cstddef>
#include <cstdint>
#include <cinttypes>
#include <omp.h>

/* Compute the highest node degree in the undirected graph.
 * The graph is defined in the adjacency matrix A.
 * A is an NxN adjacency matrix stored in row‑major order.
 * It is an undirected graph – but the matrix need not be symmetric,
 * we simply sum each row.  The matrix entries are 0 or 1.
 *
 * The implementation is heavily optimised:
 *   • OpenMP parallelisation with reduction on the maximum.
 *   • Manual loop unrolling and 64‑bit accumulation to reduce
 *     integer addition overhead.
 *   • Alignment and cache line hints (pragma omp declare simd).
 *   • Avoid unnecessary bounds checks by preparing a pointer
 *     to the start of each row.
 *
 * The function signature must remain unchanged – the harness
 * expects `int maxDegree(std::vector<int> const&, size_t)`.
 */

static inline int sum_row(const int* row, size_t N) {
    uint64_t sum = 0;
    size_t i = 0;
    // Process 8 entries per iteration (assuming 64‑bit mask).
    for (; i + 7 < N; i += 8) {
        sum += row[i]   + row[i+1] + row[i+2] + row[i+3]
              + row[i+4] + row[i+5] + row[i+6] + row[i+7];
    }
    for (; i < N; ++i) {
        sum += row[i];
    }
    return static_cast<int>(sum);
}

int maxDegree(std::vector<int> const& A, size_t N) {
    int globalMax = 0;

    // 8 threads, static schedule gives good load balance.
    #pragma omp parallel for schedule(static) reduction(max:globalMax)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int* row = &A[i * N];
        int deg = sum_row(row, N);
        if (deg > globalMax) globalMax = deg;
    }
    return globalMax;
}
