/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(const std::vector<int>& image, std::array<std::size_t, 256>& bins) noexcept {
    // Ensure result array starts at zero.
    std::fill(bins.begin(), bins.end(), 0);

    const std::size_t n = image.size();
    if (n == 0) return;

    // Number of OpenMP threads to use.
    const int nthreads = omp_get_max_threads();

    // Temporary per-thread accumulators
    std::vector<std::array<std::size_t, 256>> local(nthreads);
    for (int t = 0; t < nthreads; ++t)
        local[t].fill(0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, 256>& localBins = local[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const int val = image[i];
            // `val` is guaranteed 0-255 by the contract
            localBins[val] += 1;
        }
    }

    // Merge per-thread results into the final bins array
