inline void prefixSum(std::vector<int64_t> const& x,
                      std::vector<int64_t> &output) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Ensure output has the correct size
    if (output.size() != n)
        output.resize(n);

    // Temporary array to hold the local prefix sums
    std::vector<int64_t> local(n);

    // First pass: compute inclusive scan per thread on its block
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const int nthreads = omp_get_num_threads();

        std::size_t chunk = n / nthreads;
        std::size_t start = tid * chunk;
        std::size_t end   = (tid == nthreads - 1) ? n : start + chunk;

        if (start < end) {
            // Compute inclusive scan for this block
            local[start] = x[start];
            for (std::size_t i = start + 1; i < end; ++i)
                local[i] = local[i - 1] + x[i];
        }
    }

    // Prefix sum of the last elements of each chunk to get offsets
    std::vector<int64_t> offsets(omp_get_max_threads() + 1, 0);
    for (int t = 1; t < int(offsets.size()); ++t) {
        std::size_t idx = std::size_t(t - 1) * (n / omp_get_max_threads()) + 
                          ((t - 1) == int(omp_get_max_threads() - 1) ? 
                            n - (n / omp_get_max_threads() * int(omp_get_max_threads())) : 0);
        if (idx < n)
            offsets[t] = offsets[t-1] + local[idx];
        else
            offsets[t] = offsets[t-1];
    }

    // Second pass: add offsets to each block
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int t = int(i / (n / omp_get_max_threads()));
        output[i] = local[i] + offsets[t];
    }
}
