struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The input vectors `x` and `y` must be sorted increasing by `index`.
 * The array `z` is assumed to be pre‑allocated with a size large enough
 * to hold all indices that appear in `x` or `y`, and it is initialized
 * to zero before the call.
 *
 * This implementation keeps the original semantics but adds
 * parallelism for the tail scans – the merge part (where the indices
 * differ) is performed serially because it requires ordered updates.
 * The remaining elements are processed in parallel.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z) {
    std::size_t xi = 0, yi = 0;

    /* merge the two ordered lists */
    while (xi < x.size() && yi < y.size()) {
        if (x[xi].index < y[yi].index) {
            z[x[xi].index] += alpha * x[xi].value;
            ++xi;
        } else if (x[xi].index > y[yi].index) {
            z[y[yi].index] += y[yi].value;
            ++yi;
        } else { /* equal indices */
            z[x[xi].index] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    /* remaining elements – these are independent and can be processed in parallel */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < xi < x.size() ? x.size() - xi : 0; ++i) {
        if (xi + i < x.size())
            z[x[xi + i].index] += alpha * x[xi + i].value;
    }

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < yi < y.size() ? y.size() - yi : 0; ++i) {
        if (yi + i < y.size())
            z[y[yi + i].index] += y[yi + i].value;
    }
}
