inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<double>& r,
                std::vector<double>& i)
{
    const size_t N = x.size();
    std::vector<std::complex<double>> f(x);           // in‑place transform

    /* ---------- precompute bit‑reversal table ---------- */
    const size_t logN = static_cast<size_t>(std::log2(N));
    std::vector<size_t> rev(N);
    for (size_t n = 0; n < N; ++n) {
        size_t v = n;
        v = (v << 16) | (v >> 16);
        v = ((v & 0x0f0f0f0f) << 4) | ((v & 0xf0f0f0f0) >> 4);
        v = ((v & 0x00ff00ff) << 8) | ((v & 0xff00ff00) >> 8);
        rev[n] = v >> (32 - logN);
    }

    /* ---------- iterative radix‑2 Cooley‑Tukey ---------- */
    const double PI = 3.14159265358979323846264338327950288L;
    for (size_t s = 1; s <= logN; ++s) {
        const size_t m = 1ull << s;          // stage size
        const size_t m2 = m >> 1;
        const double theta = -2.0 * PI / m;
        const std::complex<double> w_m(std::cos(theta), std::sin(theta));

        /* parallel butterfly loop */
#pragma omp parallel for schedule(static)
        for (size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = 0; j < m2; ++j) {
                const size_t a = k + j;
                const size_t b = a + m2;
                const std::complex<double> t = w * f[b];
                f[b] = f[a] - t;
                f[a] += t;
                w *= w_m;
            }
        }
    }

    /* ---------- bit‑reverse permutation ---------- */
#pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n) {
        size_t j = rev[n];
        if (j > n) {
            std::swap(f[n], f[j]);
        }
    }

    /* ---------- split real and imaginary parts ---------- */
    r.resize(N);
    i.resize(N);
#pragma omp parallel for schedule(static)
    for (size_t n = 0; n < N; ++n) {
        r[n] = f[n].real();
        i[n] = f[n].imag();
    }
}
