/*
   Compute one iteration of a 3‑point 1‑D Jacobi stencil.
   For each element i:
       output[i] = (input[i‑1] + input[i] + input[i+1]) / 3
   Elements outside the input boundaries contribute 0.
   The implementation below preserves the exact semantics of the
   original code while providing standalone, data‑level and
   parallel optimisations.
*/
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;                     // Guard for empty input

    const double *restrict in  = input.data();
          double *restrict out = output.data();

    /* Reduce the constant division by using a reciprocal */
    const double inv3 = 1.0 / 3.0;

    /* Handle the first element separately (no left neighbour) */
    out[0] = (in[0] + in[1]) * inv3;

    /* Parallelised core loop: safe because each iteration writes to a unique
       slot in the output vector. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        out[i] = (in[i-1] + in[i] + in[i+1]) * inv3;
    }

    /* Handle the last element separately (no right neighbour) */
    if (n > 1) {
        out[n-1] = (in[n-2] + in[n-1]) * inv3;
    }
}
