struct COOElement { size_t row, column; double value; };

//====================================================================
// LU factorisation of a sparse NxN matrix in COO format.
// The result is written into the row‑major dense matrices L and U.
//====================================================================
void luFactorize(std::vector<COOElement> const& A, std::vector<double> &L,
                 std::vector<double> &U, size_t N)
{
    // Allocate dense matrices if not already sized
    if (L.size() != N * N) L.resize(N * N, 0.0);
    if (U.size() != N * N) U.resize(N * N, 0.0);

    // Build a dense copy of A
    std::vector<double> fullA(N * N, 0.0);
    for (auto const& e : A)
        fullA[e.row * N + e.column] = e.value;

    // Main LU loop – rows are processed sequentially because each
    // row depends on all previously computed ones.  Within a row,
    // the columns can be handled in parallel.
    for (size_t i = 0; i < N; ++i) {

        // ------------------------------------------------------------------
        // U[i,:] – upper part (including diagonal)
        // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
        for (size_t j = i; j < N; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        // ------------------------------------------------------------------
        // L[i,:] – lower part (excluding diagonal)
        // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
        for (size_t j = 0; j < i; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = sum / U[j * N + j];
        }

        // Diagonal of L is always 1
        L[i * N + i] = 1.0;
    }
}
