#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
*/
inline void solveLinearSystem(const std::vector<COOElement> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              size_t N)
{
   /* data layout: flat array for better cache utilisation */
   std::vector<double> mat(N * N, 0.0);
   std::vector<double> rhs = b;
   x.assign(N, 0.0);

   /* fill matrix */
   for (const auto &e : A)
      mat[e.row * N + e.column] = e.value;

   /* Gaussian elimination with partial pivoting */
   for (size_t i = 0; i < N; ++i) {
      /* 1. find pivot row (parallel) */
      size_t pivot = i;
      double maxAbs = std::abs(mat[i * N + i]);

      #pragma omp parallel for reduction(max:maxAbs) schedule(static)
      for (size_t r = i + 1; r < N; ++r) {
         double val = std::abs(mat[r * N + i]);
         if (val > maxAbs) {
            maxAbs = val;
            #pragma omp critical
            pivot = r;
         }
      }

      /* 2. swap pivot row with current row (column by column) */
      if (pivot != i) {
         for (size_t c = i; c < N; ++c) {
            std::swap(mat[pivot * N + c], mat[i * N + c]);
         }
         std::swap(rhs[pivot], rhs[i]);
      }

      /* 3. elimination below pivot */
      double pivotVal = mat[i * N + i];
      for (size_t r = i + 1; r < N; ++r) {
         double factor = -mat[r * N + i] / pivotVal;
         for (size_t c = i; c < N; ++c) {
            mat[r * N + c] += factor * mat[i * N + c];
         }
         rhs[r] += factor * rhs[i];
      }
   }

   /* back substitution */
   for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
      double sum = rhs[i];
      for (int j = static_cast<int>(i) + 1; j < static_cast<int>(N); ++j) {
         sum -= mat[i * N + j] * x[j];
      }
      x[i] = sum / mat[i * N + i];
   }
}
