/* Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
   Exact semantics of the original implementation are preserved.
   This implementation performs two parallel for passes:
   1. Compute the minimum value of each chunk owned by a thread.
   2. Propagate the prefix minima and write the result back to x.
   The algorithm is O(n) and benefits from up to 8 OpenMP threads. */
inline void partialMinimums(std::vector<float> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    const int num_threads = std::min(static_cast<int>(n), omp_get_max_threads());
    std::vector<float> chunk_min(num_threads, std::numeric_limits<float>::max());
    std::vector<std::size_t> chunk_start(num_threads);
    std::vector<std::size_t> chunk_end(num_threads);

    /* Divide the array into contiguous chunks for each thread. */
    const std::size_t chunk_size = (n + num_threads - 1) / num_threads;
    for (int t = 0; t < num_threads; ++t) {
        chunk_start[t] = t * chunk_size;
        chunk_end[t]   = std::min(chunk_start[t] + chunk_size, n);
    }

    /* First pass: each thread finds the minimum in its chunk. */
#pragma omp parallel num_threads(num_threads)
    {
        const int tid = omp_get_thread_num();
        float local_min = std::numeric_limits<float>::max();
        for (std::size_t i = chunk_start[tid]; i < chunk_end[tid]; ++i)
            local_min = std::min(local_min, x[i]);
        chunk_min[tid] = local_min;
    }

    /* Compute prefix minima for each chunk boundary. */
    std::vector<float> prefix_min(num_threads);
    float acc = std::numeric_limits<float>::max();
    for (int t = 0; t < num_threads; ++t) {
        acc = std::min(acc, chunk_min[t]);
        prefix_min[t] = acc;
    }

    /* Second pass: each thread writes the correct minimum to its elements.
       The value for element i is the minimum of all elements up to i,
       which is prefix_min[chunk_of_i] and possibly a smaller value from the
       same chunk before i. */
#pragma omp parallel for schedule(static, 1) num_threads(num_threads)
    for (int t = 0; t < num_threads; ++t) {
        // Keep track of the minimum seen so far within this chunk.
        float local_prefix = prefix_min[t];
        for (std::size_t i = chunk_start[t]; i < chunk_end[t]; ++i) {
            local_prefix = std::min(local_prefix, x[i]);
            x[i] = local_prefix;
        }
    }
}
