                                          {-1,  8, -1},
                                          {-1, -1, -1} };

/**
 * Convolve the 3×3 edge kernel with a grayscale image.
 * The kernel coefficients are applied with zero‑padding outside the image.
 * The output for each pixel is clipped to [0, 255].
 *
 * @param imageIn  input image stored in row‑major order (size N×N)
 * @param imageOut output image (size N×N) – must be pre‑allocated
 * @param N        image dimension
 */
void convolveKernel(std::vector<int> const& imageIn,
                    std::vector<int> &imageOut,
                    std::size_t N)
{
    // Use pointer arithmetic for minimal overhead
    const int *in  = imageIn.data();
    int       *out = imageOut.data();

    // Parallelise the outer loop – each row is independent
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t rowOff = i * N;
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;

            // Unroll the 3×3 kernel – zero padding is handled by bounds tests
            for (int ki = -1; ki <= 1; ++ki) {
                std::size_t x = i + ki;
                if (x >= N) continue;   // outside vertical bounds
                const int *rowBase = in + x * N;

                for (int kj = -1; kj <= 1; ++kj) {
                    std::size_t y = j + kj;
                    if (y >= N) continue;   // outside horizontal bounds
                    sum += rowBase[y] * edgeKernel[ki + 1][kj + 1];
                }
            }

            // Clamp to [0,255] – compiler may replace with integer intrinsics
            out[rowOff + j] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
}
