#include <omp.h>

struct Point
{
    double x, y;
};

inline double cross(const Point &a, const Point &b, const Point &c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull)
{
    const std::size_t n = points.size();
    if (n < 3) {            // Trivial cases
        hull = points;
        return;
    }

    /* ---------- 1. Sort points by (x, y) lexicographically ------------- */
    std::vector<Point> pts(points);   // copy once
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    /* ---------- 2. Build convex hull (Monotone chain) ------------------ */
    std::vector<Point> res;
    res.reserve(2 * n);          // maximum possible size

    // Build lower hull
    for (const auto &p : pts) {
        while (res.size() >= 2 &&
               cross(res[res.size() - 2], res[res.size() - 1], p) <= 0)
            res.pop_back();
        res.push_back(p);
    }

    // Build upper hull, skipping the last point of lower hull to avoid duplication
    const std::size_t lower_size = res.size();
    for (std::size_t i = pts.size() - 1; i > 0; --i) {
        const auto &p = pts[i - 1];
        while (res.size() > lower_size &&
               cross(res[res.size() - 2], res[res.size() - 1], p) <= 0)
            res.pop_back();
        res.push_back(p);
    }

    // The last point is same as the first one; remove it
    if (!res.empty())
        res.pop_back();         // size now k-1

    hull = std::move(res);      // move instead of copy
}
