/* Compute one iteration of a 5‑point 2‑D Jacobi stencil on `input`
   and store the results in `output`.  The behavior is identical
   to the original version, but the implementation is highly
   parallelised and runs the inner loop in SIMD‑friendly order. */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              size_t N)
{
    constexpr double inv5 = 0.2;          // 1/5, avoids a division each time
    const double* in  = input.data();
    double*       out = output.data();

    /* Parallelise the two nested loops.  Use a parallel for
       with collapse(2) so that each thread gets a balanced
       chunk of (i , j) work. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t rowOff = i * N;
        const size_t prevRow = (i > 0)   ? rowOff - N : rowOff;
        const size_t nextRow = (i + 1 < N)? rowOff + N : rowOff;

        for (size_t j = 0; j < N; ++j)
        {
            double sum = in[rowOff + j];          // centre
            sum += in[prevRow + j];               // north
            sum += in[nextRow + j];               // south

            if (j > 0) sum += in[rowOff + j - 1]; // west
            if (j + 1 < N) sum += in[rowOff + j + 1]; // east

            out[rowOff + j] = sum * inv5;
        }
    }
}
