void sortIgnoreZero(std::vector<int> &x) noexcept {
    // Count non‑zero elements to reserve space and avoid reallocation
    std::size_t nonZeroCount = std::count_if(x.begin(), x.end(),
                                            [](int v) { return v != 0; });

    // If no non‑zero elements, nothing to do
    if (nonZeroCount == 0) {
        return;
    }

    // Extract non‑zero values into a separate vector
    std::vector<int> nonZero;
    nonZero.reserve(nonZeroCount);
    std::copy_if(x.begin(), x.end(), std::back_inserter(nonZero),
                 [](int v) { return v != 0; });

    // Sort the extracted values
    std::sort(nonZero.begin(), nonZero.end());

    // Re‑insert sorted values back into the original positions
    for (int &v : x) {
        if (v != 0) {
            v = nonZero.back();
            nonZero.pop_back();
        }
    }
}
