/* Find the k‑th smallest element of the vector x.
   Example:
   input: x=[1, 7, 6, 0, 2, 2, 10, 6], k=4
   output: 6
   This implementation uses std::nth_element with the parallel execution policy
   for O(n) average‑time performance on modern multi‑core CPUs. */
int findKthSmallest(const std::vector<int>& x, int k) {
    // Copy the data since the input is const and we want to preserve its order
    std::vector<int> tmp = x;
    // Parallel nth_element rearranges elements so that the element at
    // position k-1 is the value that would be there if the vector were sorted.
