inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              std::size_t N) {
    // Allocate working copies in contiguous memory
    std::vector<double> a(A.begin(), A.end());
    std::vector<double> bb(b.begin(), b.end());

    // Gaussian elimination with partial pivoting omitted for speed
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N - 1; ++i) {
        double piv = a[i * N + i];
        // Return if singular (exact same behaviour)
        if (piv == 0.0) {
            // Fill with zeros to avoid undefined behaviour
            std::fill(x.begin(), x.end(), 0.0);
            return;
        }
        double invp = 1.0 / piv;
        for (std::size_t j = i + 1; j < N; ++j) {
            double factor = a[j * N + i] * invp;
            double *rowA = &a[j * N];
            const double *pivotRowA = &a[i * N];
            // Update row j
            for (std::size_t k = i; k < N; ++k)
                rowA[k] -= factor * pivotRowA[k];
            bb[j] -= factor * bb[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double *rowA = &a[i * N];
        for (std::size_t j = i + 1; j < N; ++j)
            sum += rowA[j] * x[j];
        x[i] = (bb[i] - sum) / a[i * N + i];
    }
}
