        RedInfo thread_min{ std::numeric_limits<double>::infinity(), 0 };

        #pragma omp for nowait
        for (size_t i = 0; i < n; ++i) {
            double diff = std::fabs(x[i] - pi);
            if (diff < thread_min.val) {
                thread_min.val = diff;
                thread_min.idx = i;
