// Sort a vector of std::complex<double> by magnitude in ascending order.
// The comparator avoids the expensive sqrt by comparing squared magnitudes
// and the algorithm uses a parallel execution policy to leverage multiple cores.
inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    constexpr auto cmp = [](const std::complex<double>& a,
                           const std::complex<double>& b) noexcept
    {
        const double ra = a.real(), ia = a.imag();
        const double rb = b.real(), ib = b.imag();
        return (ra * ra + ia * ia) < (rb * rb + ib * ib);
    };

    // Parallel sort (C++17 execution policy). Falls back to sequential
    // if the compiler/standard library does not support parallel execution.
    std::sort(std::execution::par, x.begin(), x.end(), cmp);
}
