    const int *in  = input.data();
    int *      out = output.data();

    /* Parallel over rows; each thread works on a contiguous chunk of
       data and uses a local pointer to navigate the array. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base = i * N;
        const size_t belowBase = (i + 1 < N) ? base + N : 0;
        const size_t aboveBase = (i > 0) ? base - N : 0;

        for (size_t j = 0; j < N; ++j) {
            int cnt = 0;
            if (aboveBase && in[aboveBase + j]) ++cnt;
            if (belowBase && in[belowBase + j]) ++cnt;
            if (j > 0 && in[base + j - 1]) ++cnt;
            if (j + 1 < N && in[base + j + 1]) ++cnt;
            out[base + j] = (cnt == 1) ? 1 : 0;
        }
    }
