/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row‑major, x has N elements, and y has M elements.
   The implementation is identical in result to the reference version but is
   heavily optimized for modern x86‑64 CPUs with 8 hardware threads. */

inline void gemv(const std::vector<double> &A,
                 const std::vector<double> &x,
                 std::vector<double>       &y,
                 size_t M, size_t N)
{
