       - A must be contiguous in row‑major order,
       - x and y must be size N and M respectively. */
    const double *a = A.data();
    const double *xx = x.data();
          double *yy = y.data();

    /* Choose a block size that fits into L1/L2 cache.  256 bytes is the
       size of a typical cache line, 16 * 16 doubles = 2 KB, which is a good
       compromise for 2‑stage tiling. */
    constexpr size_t blockN = 64;          // outer block over columns
    constexpr size_t blockM = 256 / sizeof(double); // outer block over rows

    /* Parallelise across rows. The work is naturally embarrassingly parallel. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        double rowSum[blockM] = {0.0};
        size_t rowBase = i * N;

        /* Process columns in blocks to increase temporal locality of x. */
        for (size_t jb = 0; jb < N; jb += blockN) {
            size_t nb = (jb + blockN <= N) ? blockN : (N - jb);

            /* Unroll the inner loop to reduce loop overhead. */
            for (size_t j = 0; j < nb; ++j) {
                double aij = a[rowBase + jb + j];
                double xj  = xx[jb + j];
                yy[i] += aij * xj;
            }
        }
    }
