struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X
 *  A : M×K sparse matrix in COO format
 *  X : K×N sparse matrix in COO format
 *  Y : dense M×N row‑major matrix (output)
 *
 *  The implementation groups the COO entries by their row
 *  (for A) and by their row (for X).  Then it performs
 *  the multiplication row‑wise, which is embarrassingly
 *  parallel and avoids any write conflicts.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    // Output matrix
    Y.assign(M * N, 0.0);

    // Group A by row
    std::vector<std::vector<COOElement>> A_by_row(M);
    for (auto const& a : A) {
        A_by_row[a.row].push_back(a);
    }

    // Group X by row (which corresponds to column of A)
    std::vector<std::vector<COOElement>> X_by_row(K);
    for (auto const& x : X) {
        X_by_row[x.row].push_back(x);
    }

    // Parallel over rows of A (hence rows of Y)
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        const auto& a_row = A_by_row[i];
        if (a_row.empty()) continue;

        double* y_row = &Y[i * N];  // base pointer for row i
        for (auto const& a : a_row) {
            const auto& x_col_vec = X_by_row[a.column];
            if (x_col_vec.empty()) continue;

            double coeff = a.value;
            for (auto const& x : x_col_vec) {
                y_row[x.column] += coeff * x.value;
            }
        }
    }
}
