#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

/* In‑place iterative radix‑2 FFT.  Assumes size N is a power of two. */
static void fft_helper(std::vector<std::complex<double>>& x)
{
    const unsigned int N = static_cast<unsigned int>(x.size());
    const unsigned int logN = static_cast<unsigned int>(std::log2(N));

    /* Pre‑compute the twiddle factors */
    std::vector<std::complex<double>> W(N/2);
    const double twiddle_step = -2.0 * M_PI / N;
    for (unsigned int k = 0; k < N/2; ++k)
        W[k] = std::exp(std::complex<double>(0.0, twiddle_step * k));

    /* Iterative in‑place decimation‑in‑time */
    for (unsigned int s = 1; s <= logN; ++s) {
        const unsigned int m  = 1u << s;          // sub‑FFT size
        const unsigned int hal = m >> 1;          // half size
        const unsigned int stride = N / m;        // twiddle step

        /* Parallel butterfly loops: each thread processes a block of indices */
#pragma omp parallel for schedule(static)
        for (unsigned int k = 0; k < N; k += m) {
            for (unsigned int j = 0; j < hal; ++j) {
                const unsigned int index1 = k + j;
                const unsigned int index2 = index1 + hal;
                const std::complex<double> t = W[j * stride] * x[index2];
                x[index2] = x[index1] - t;
                x[index1] += t;
            }
        }
    }

    /* Bit‑reversal permutation */
    for (unsigned int i = 0; i < N; ++i) {
        unsigned int j = i;
        j = ((j >> 1) & 0x55555555u) | ((j & 0x55555555u) << 1);
        j = ((j >> 2) & 0x33333333u) | ((j & 0x33333333u) << 2);
        j = ((j >> 4) & 0x0f0f0f0fu) | ((j & 0x0f0f0f0fu) << 4);
        j = ((j >> 8) & 0x00ff00ffu) | ((j & 0x00ff00ffu) << 8);
        j = (j >> 16) | (j << 16);
        j >>= (32 - logN);
        if (j > i)
            std::swap(x[i], x[j]);
    }
}

/* Inverse FFT: conjugate, forward FFT, conjugate again, and scale */
inline void ifft(std::vector<std::complex<double>>& x)
{
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    fft_helper(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    const double inv_n = 1.0 / static_cast<double>(x.size());
    std::transform(x.begin(), x.end(), x.begin(),
                   [inv_n](const std::complex<double>& v){ return v * inv_n; });
}
