    std::sort(vals.begin(), vals.end(),
              [](const auto& a, const auto& b) { return a.first < b.first; });

    // Fill the output ranks.
    for (std::size_t rank = 0; rank < n; ++rank) {
        ranks_[vals[rank].second] = rank;
    }
}
