    for (std::size_t i = 0; i < N; ++i) {
        std::size_t b = i;
        b = ((b & 0xaaaaaaaa) >> 1) | ((b & 0x55555555) << 1);
        b = ((b & 0xcccccccc) >> 2) | ((b & 0x33333333) << 2);
        b = ((b & 0xf0f0f0f0) >> 4) | ((b & 0x0f0f0f0f) << 4);
        b = ((b & 0xff00ff00) >> 8) | ((b & 0x00ff00ff) << 8);
        b = ((b >> 16) | (b << 16));
        rev[i] = (b >> (32 - logN));
    }

    // ---- Bit‑reversal re‑ordering (in‑place) ----
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }

    // ---- Iterative FFT stages ----
    //   stage level s : block size = 2^s
    for (std::size_t s = 1; s <= logN; ++s) {
        const std::size_t m  = 1 << s;          // size of butterfly group
        const std::size_t mh = m >> 1;          // half size
        const double angle = -M_PI / mh;        // negative for forward FFT
        const std::complex<double> w_m = std::exp(std::complex<double>(0.0, angle));

        // Parallelise over independent butterfly groups
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m) {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < mh; ++j) {
                std::complex<double> t = w * output[k + j + mh];
                std::complex<double> u = output[k + j];
                output[k + j]     = u + t;
                output[k + j + mh] = u - t;
                w *= w_m;
            }
        }
    }
}
