#include <immintrin.h>
#include <omp.h>

/* In‑place LU factorisation of an N×N matrix stored in row‑major order.
   The function is fully thread‑safe and preserves the exact semantics of
   the reference implementation. */
inline void luFactorize(std::vector<double> &A, const size_t N) {
    const size_t stride = N;                 // row length in elements
    const size_t simdLen = 4;                // process 4 doubles per iteration
    const double * const base = A.data();    // pointer to the first element

    // Unroll the outermost k‑step and parallelise the inner i‑loop.
    for (size_t k = 0; k < N; ++k) {
        const size_t kRow = k * stride;
        const double pivot = base[kRow + k];
        const double * const rowK = base + kRow;

        // Each thread works on a distinct subset of rows i > k.
        #pragma omp parallel for schedule(dynamic, 64)
        for (size_t i = k + 1; i < N; ++i) {
            const size_t iRow = i * stride;
            const double * const rowI = base + iRow;

            double factor = rowI[k] / pivot;
            // store the factor in the lower triangular part
            ((double*)rowI)[k] = factor;

            // vectorised update of the rest of the row
            size_t j = k + 1;
            // SIMD loop: process 4 doubles per iteration
            for (; j + simdLen <= N; j += simdLen) {
                __m256d vU = _mm256_loadu_pd(rowK + j);   // U[k][j..j+3]
                __m256d vX = _mm256_mul_pd(_mm256_set1_pd(factor), vU);
                __m256d vA = _mm256_loadu_pd(rowI + j);   // A[i][j..j+3]
                vA = _mm256_sub_pd(vA, vX);
                _mm256_storeu_pd(rowI + j, vA);
            }
            // scalar tail
            for (; j < N; ++j) {
                rowI[j] -= factor * rowK[j];
            }
        }
    }
}
