#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <algorithm>
#include <omp.h>

/* Fast Game‑of‑Life step implementation.
 * Exactly preserves the behaviour of the original reference.
 *
 * All arithmetic is performed with 32‑bit integers to avoid overflow.
 * OpenMP is used to parallelise across the whole matrix.
 * The neighbour count is accumulated in a small stencil to minimise branching.
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N)
{
    // Safety: caller guarantees the vectors have N*N elements.
    const size_t NN = N * N;

    // Work with raw pointers for speed.
    const int32_t *in  = input.data();
    int32_t       *out = output.data();

    // Using a parallel for over all rows; OpenMP first‑private is unnecessary
    // because each iteration writes to a distinct index range.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t iN = i * N;
        const size_t iNm1 = (i > 0)   ? (i-1) * N : 0;
        const size_t iNp1 = (i < N-1) ? (i+1) * N : 0;

        for (size_t j = 0; j < N; ++j) {
            int32_t sum = 0;

            // Direct neighbours (avoid branch explosion)
            if (i > 0)     sum += in[iNm1 + j];
            if (i < N-1)   sum += in[iNp1 + j];
            if (j > 0)     sum += in[iN   + j-1];
            if (j < N-1)   sum += in[iN   + j+1];

            // Diagonal neighbours
            if (i > 0 && j > 0)           sum += in[iNm1 + j-1];
            if (i > 0 && j < N-1)         sum += in[iNm1 + j+1];
            if (i < N-1 && j > 0)         sum += in[iNp1 + j-1];
            if (i < N-1 && j < N-1)       sum += in[iNp1 + j+1];

            const int32_t cur = in[iN + j];
            if (cur == 1) {
                // Live cell survives with 2 or 3 neighbours
                out[iN + j] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                // Dead cell becomes alive if exactly 3 neighbours
                out[iN + j] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
