#include <omp.h>

// ---------------------------------------------------------------
// In‑place radix‑2 FFT (forward) followed by full complex conjugation.
// ---------------------------------------------------------------
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // -----------------------------------------------------------
    // 1. Bit reversal *before* FFT for cache‑friendly access.
    // -----------------------------------------------------------
    const std::size_t m = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = ((i & 0xaaaaaaaaaaaaaaaaULL) >>  1) |
                          ((i & 0x5555555555555555ULL) <<  1) |
                          ((i & 0xccccccccccccccccULL) >>  2) |
                          ((i & 0x3333333333333333ULL) <<  2) |
                          ((i & 0xf0f0f0f0f0f0f0f0ULL) >>  4) |
                          ((i & 0x0f0f0f0f0f0f0f0fULL) <<  4) |
                          ((i & 0xff00ff00ff00ff00ULL) >>  8) |
                          ((i & 0x00ff00ff00ff00ffULL) <<  8) |
                          ((i & 0xffff0000ffff0000ULL) >> 16) |
                          ((i & 0x0000ffff0000ffffULL) << 16);
        rev >>= (64 - m);
        if (rev > i) std::swap(x[i], x[rev]);
    }

    // -----------------------------------------------------------
    // 2. Pre‑compute twiddle factors.
    // -----------------------------------------------------------
    std::vector<std::complex<double>> twiddle(N >> 1);
    const std::complex<double> pi = std::acos(-1.0);
    for (std::size_t k = 0; k < (N >> 1); ++k) {
        double angle = -2 * pi * static_cast<double>(k) / static_cast<double>(N);
        twiddle[k] = std::exp(std::complex<double>(0, angle));
    }

    // -----------------------------------------------------------
    // 3. Iterative radix‑2 FFT (Danielson–Lanczos).
    // -----------------------------------------------------------
    std::size_t halfSize = 1;
    while (halfSize < N) {
        const std::size_t step = halfSize << 1;
        for (std::size_t i = 0; i < N; i += step) {
            for (std::size_t j = 0; j < halfSize; ++j) {
                const std::complex<double> t = twiddle[(j * N) / step] * x[i + j + halfSize];
                const std::complex<double> u = x[i + j];
                x[i + j]           = u + t;
                x[i + j + halfSize] = u - t;
            }
        }
        halfSize = step;
    }

    // -----------------------------------------------------------
    // 4. Concurrent complex conjugation.
    // -----------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
