#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
    int startTime, duration;
    float value;
};

/// Parallel mergesort (in-place) that preserves the same ordering semantics
/// as std::sort with the provided comparator.
void sortByStartTime(std::vector<Result> &results)
{
    if (results.size() < 2)
        return;

    const size_t  n          = results.size();
    const int     max_threads = omp_get_max_threads();
    const size_t  block      = (n + max_threads - 1) / max_threads;   // ceil

    /* ------------------------------------------------------------------
       1.  Each thread sorts its own block serially.
      ------------------------------------------------------------------ */
#pragma omp parallel for schedule(static, 1) // max_threads iterations
    for (int t = 0; t < max_threads; ++t) {
        size_t lo = t * block;
        if (lo >= n) continue;                      // no work for this thread
        size_t hi = std::min(lo + block, n);        // exclusive
        std::sort(results.begin() + lo, results.begin() + hi,
                    [](const Result& a, const Result& b) {
                        return a.startTime < b.startTime;
                    });
    }

    /* ------------------------------------------------------------------
       2.  Merge the sorted blocks pairwise.
           The merge steps are performed in log₂(max_threads) stages.
           Each merge stage can be parallelised.
      ------------------------------------------------------------------ */
    size_t current_block = block;
    while (current_block < n) {
        size_t stride = current_block * 2;
        const size_t num_merges = (n + stride - 1) / stride;

#pragma omp parallel for schedule(static, 1)
        for (int i = 0; i < num_merges; ++i) {
            size_t lo = i * stride;
            size_t mid = std::min(lo + current_block, n);
            size_t hi = std::min(lo + stride, n);
            if (mid >= hi) continue;             // nothing to merge
            std::inplace_merge(results.begin() + lo,
                               results.begin() + mid,
                               results.begin() + hi);
        }
        current_block = stride;
    }
}
