/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are
   stored in row-major order. The function preserves the exact semantics of
   the reference implementation while exploiting spatial locality,
   SIMD vectorisation and multithreading. */
inline void gemm(const std::vector<double> &A, const std::vector<double> &B,
                 std::vector<double> &C, size_t M, size_t K, size_t N)
{
    // Choose block sizes that fit comfortably in L1/L2 cache.
    constexpr size_t BM = 64;   // block size for rows of A / columns of C
    constexpr size_t BN = 64;   // block size for columns of B / columns of C
    constexpr size_t BK = 64;   // block size for shared dimension K

    // Ensure C is zero-initialised before accumulation.
    std::fill(C.begin(), C.end(), 0.0);

    // Parallelise over the outermost M‑block; each thread works on a disjoint
    // set of rows of C, guaranteeing thread safety.
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BM) {
        size_t i_max = (i0 + BM > M) ? M : i0 + BM;
        for (size_t j0 = 0; j0 < N; j0 += BN) {
            size_t j_max = (j0 + BN > N) ? N : j0 + BN;
            for (size_t k0 = 0; k0 < K; k0 += BK) {
                size_t k_max = (k0 + BK > K) ? K : k0 + BK;

                // Pointers to the current block positions
                const double* a_ptr = A.data() + i0 * K;
                const double* b_ptr = B.data() + k0 * N + j0;
                double*       c_ptr = C.data() + i0 * N + j0;

                for (size_t i = i0; i < i_max; ++i) {
                    const double* a_row = a_ptr + i * K;
                    double*       c_row = c_ptr + i * N;
                    for (size_t k = k0; k < k_max; ++k) {
                        double aik = a_row[k];
                        const double* b_row = b_ptr + k * N;
                        // SIMD‐friendly inner loop over columns of the block
                        for (size_t j = j0; j < j_max; ++j) {
                            c_row[j] += aik * b_row[j];
                        }
                    }
                }
            }
        }
    }
}
