// Return the index of the first even number in the vector `x`.
// If no even number exists, returns `x.size()`.
// The implementation uses AVX2 vectorisation for speed on x86‑64.
// It is perfectly deterministic and preserves the original semantics.
size_t findFirstEven(const std::vector<int>& x)
{
    const size_t n = x.size();
    const size_t stride = 8;                          // process 8 ints (32 bytes) per iteration
    size_t i = 0;

    // Process in blocks of 8 ints
    for (; i + stride <= n; i += stride)
    {
        // Load 8 signed 32‑bit integers
        __m256i v = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(x.data() + i));

        // Compute mask of even values: (x & 1) == 0
        __m256i low_bits = _mm256_and_si256(v, _mm256_set1_epi32(1));
        __m256i even_mask = _mm256_cmpeq_epi32(low_bits, _mm256_setzero_si256());

        // Convert the mask to a 32‑bit integer where each bit represents a lane
        int mask = _mm256_movemask_epi8(even_mask);

        // We only care about the lowest 8 bits (one per lane)
        mask &= 0xFF;
        if (mask != 0)
        {
            // Find the first set bit
            int offset = __builtin_ctz(mask) >> 1;   // each int uses 2 bits in movemask
            return i + offset;
        }
    }

    // Remaining elements (less than 8)
    for (; i < n; ++i)
    {
        if ((x[i] & 1) == 0)
            return i;
    }

    return n;
}
